  ('disabled-57f41407-moex-00516', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者非民事訴訟法規定起訴前應經調解之事件？', '["基於故意傷害之侵權行為法律關係請求給付新臺幣（下同）60萬元", "基於隱名合夥關係請求給付60萬元", "母女間請求返還消費借貸款60萬元", "因醫療糾紛請求債務不履行損害賠償60萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00517', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '對於適用簡易訴訟程序之第一審判決提起上訴，其第二審程序應由何法院 審理？', '["原裁判簡易庭之合議庭", "管轄之地方法院合議庭", "高等法院", "高等法院之分院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00518', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何訴訟標的金額或價額以下之請求給付金錢或其他代替物或有價證 券訴訟事件，當事人得合意適用小額訴訟程序？', '["新臺幣90萬元", "新臺幣75萬元", "新臺幣60萬元", "新臺幣50萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00519', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲起訴請求乙返還借款新臺幣（下同）400 萬元，乙抗辯已全數清償，第 一審法院以乙之抗辯有理由，判決甲全部敗訴。甲不服，提起上訴。第二 審法院認定乙僅清償200萬元，就其餘未清償部分，廢棄第一審法院駁回 甲此部分請求之判決，改判命乙應返還甲200萬元，並駁回甲其餘上訴。 乙就其敗訴部分，全部聲明不服，提起第三審上訴。關於第三審法院之審 理，下列敘述何者正確？', '["第三審之判決，應經言詞辯論為之，甲雖未提起第三審上訴，仍得於第 三審言詞辯論終結前，就第二審法院駁回其上訴部分，提起附帶上訴", "如甲預扣利息100萬元，僅交付300萬元與乙，乙於第三審上訴理由始 為此項抗辯，因消費借貸為要物契約，涉及法律適用正確與否，第三審 法院仍得依職權調查之", "乙於第三審上訴理由始抗辯：縱認伊未清償，甲主張之請求權亦已罹於 消滅時效。因是否罹於時效之事實於法院已顯著，無庸當事人為舉證， 第三審法院得依職權斟酌之", "乙於第三審上訴理由抗辯其於第二審言詞辯論終結後，已全數清償，並 提出甲親簽之收據為證，第三審法院亦不得斟酌之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00520', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於抗告、再抗告程序，下列敘述何者錯誤？', '["甲對乙起訴請求返還借款新臺幣（下同）200 萬元，第一審法院以甲未 繳納裁判費，起訴不合法為由，裁定駁回甲之起訴，甲提起抗告，第二 審法院認甲抗告為無理由，裁定駁回甲之抗告，甲對於該第二審裁定得 向最高法院提起再抗告", "甲對乙起訴請求返還借款200萬元，第一審法院以甲未繳納裁判費，起 訴不合法為由，裁定駁回甲之起訴，甲提起抗告，如第二審法院以甲提 起抗告已逾 10 日不變期間，抗告不合法為由，裁定駁回甲之抗告，甲 對於該第二審裁定得向最高法院提起再抗告", "丙對丁起訴請求離婚，於第二審訴訟程序中，丙以承審之受命法官審判 不公為由，聲請該法官迴避，經第二審法院裁定駁回，丙對於該裁定得 向最高法院提起抗告", "丙對丁起訴請求離婚，丙於第二審追加請求丁賠償200萬元，第二審法 院認其追加之訴為不合法，以裁定駁回丙追加之訴，丙對於該裁定得向 最高法院提起抗告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00521', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '再審原告依民事訴訟法第 496 條第 1 項第 13 款規定，以發現未經斟酌之 證物為由，對於原第二審及第三審確定判決同時提起再審之訴，應由何法 院管轄？', '["專屬原第二審法院管轄", "專屬第三審法院管轄", "原第二審法院或第三審法院均可管轄", "專屬再審被告住所地之原第一審法院管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00522', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於再審事由，下列敘述何者正確？', '["再審事由中之適用法規顯有錯誤，是指判決不備理由或理由矛盾", "再審事由中之判決法院之組織不合法，是指管轄錯誤", "再審事由中之參與裁判之法官關於該訴訟違背職務犯刑事上之罪，以 其行為足以影響原判決之基礎者為限", "再審事由中之當事人發現就同一訴訟標的在前已有確定判決或和解、 調解，包括雙方在該事件起訴前，已經訂有和解契約之情形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00523', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於第三人撤銷訴訟程序，下列敘述何者錯誤？', '["提起第三人撤銷之訴，係對於確定之終局判決為之", "判決之當事人本人不能提起第三人撤銷之訴", "為統一法律上見解，第三人提起撤銷之訴，專屬最高法院管轄", "提起第三人撤銷之訴，並無當然停止原確定判決執行之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
